export interface StyleVector {
  classical: number;
  modern: number;
  natural: number;
  geometric: number;
  luxury: number;
}

export interface WoodTensor {
  angle: number;
  reflectivity: number;
  grainComplexity: number;
  warmth: number;
  depth: number;
}

export interface DesignState {
  targetVector: StyleVector | null;
  currentAngle: number;
  optimalAngle: number;
  isProcessing: boolean;
  generatedImageUrl: string | null;
  uploadedImage: string | null;
  prompt: string;
}

export enum ProcessingStep {
  IDLE = 'IDLE',
  ENCODING_TARGET = 'ENCODING_TARGET',
  ENCODING_WOOD = 'ENCODING_WOOD',
  OPTIMIZING = 'OPTIMIZING',
  GENERATING = 'GENERATING'
}

import { WoodTensor, StyleVector } from './types';

export const MOCK_WOOD_TENSORS: WoodTensor[] = Array.from({ length: 19 }, (_, i) => {
  const angle = i * 10;
  const rad = (angle * Math.PI) / 180;
  return {
    angle,
    // Simulate goniometric changes in optical properties
    reflectivity: 0.5 + 0.4 * Math.sin(rad),
    grainComplexity: 0.3 + 0.6 * Math.cos(rad / 2),
    warmth: 0.6 + 0.3 * Math.sin(rad * 2),
    depth: 0.4 + 0.5 * Math.abs(Math.cos(rad))
  };
});

export const INITIAL_STYLE: StyleVector = {
  classical: 0.5,
  modern: 0.5,
  natural: 0.5,
  geometric: 0.5,
  luxury: 0.5
};

import { GoogleGenAI, Type } from "@google/genai";
import { StyleVector, WoodTensor } from "../types";

export class GeminiService {
  private ai: GoogleGenAI;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  }

  /**
   * Layer 2: Stream A - Target Encoder
   * Analyzes an uploaded image to extract semantic style vectors.
   */
  async encodeTargetStyle(base64Image: string): Promise<StyleVector> {
    const response = await this.ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: [
        {
          parts: [
            { inlineData: { data: base64Image.split(',')[1], mimeType: 'image/jpeg' } },
            { text: "Analyze the furniture style in this image and return a style vector. Focus on historical context (classical), contemporary trends (modern), organic vs geometric shapes, and perceived luxury level." }
          ]
        }
      ],
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            classical: { type: Type.NUMBER },
            modern: { type: Type.NUMBER },
            natural: { type: Type.NUMBER },
            geometric: { type: Type.NUMBER },
            luxury: { type: Type.NUMBER }
          },
          required: ["classical", "modern", "natural", "geometric", "luxury"]
        }
      }
    });

    return JSON.parse(response.text);
  }

  /**
   * Layer 3: Parametric Mapping & Prompt Generation
   */
  async generateSemanticPrompt(style: StyleVector, wood: WoodTensor): Promise<string> {
    const response = await this.ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Generate a highly technical and descriptive prompt for a high-end furniture visualization.
      Style Context: Classical ${style.classical}, Modern ${style.modern}, Natural ${style.natural}, Luxury ${style.luxury}.
      Wood Property: Golden Silk Phoebe (Nanmu) wood at ${wood.angle} degrees light incidence. 
      The wood grain should show dynamic chatoyancy, silk-like fibers, and deep amber-gold reflections.
      Technical details: Depth map guidance, physical accuracy, cinematic lighting, 8k resolution.`,
    });
    return response.text;
  }

  /**
   * Layer 4: Generative Visualization
   */
  async generateFurniture(prompt: string, referenceImageBase64?: string): Promise<string> {
    const parts: any[] = [{ text: prompt }];
    if (referenceImageBase64) {
      parts.push({
        inlineData: {
          data: referenceImageBase64.split(',')[1],
          mimeType: 'image/jpeg'
        }
      });
    }

    const response = await this.ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: { parts },
      config: {
        imageConfig: {
          aspectRatio: "1:1"
        }
      }
    });

    let imageUrl = '';
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        imageUrl = `data:image/png;base64,${part.inlineData.data}`;
        break;
      }
    }
    return imageUrl;
  }
}

import React from 'react';
import { 
  Radar, RadarChart as ReRadarChart, PolarGrid, 
  PolarAngleAxis, PolarRadiusAxis, ResponsiveContainer 
} from 'recharts';
import { StyleVector } from '../types';

interface RadarChartProps {
  data: StyleVector;
}

export const RadarChart: React.FC<RadarChartProps> = ({ data }) => {
  const chartData = [
    { subject: 'Classical', A: data.classical * 100, fullMark: 100 },
    { subject: 'Modern', A: data.modern * 100, fullMark: 100 },
    { subject: 'Natural', A: data.natural * 100, fullMark: 100 },
    { subject: 'Geometric', A: data.geometric * 100, fullMark: 100 },
    { subject: 'Luxury', A: data.luxury * 100, fullMark: 100 },
  ];

  return (
    <div className="w-full h-64 bg-stone-800/50 rounded-xl p-4 border border-stone-700">
      <h3 className="text-xs font-bold uppercase tracking-wider text-stone-400 mb-2">Semantic Imagery Radar</h3>
      <ResponsiveContainer width="100%" height="100%">
        <ReRadarChart cx="50%" cy="50%" outerRadius="80%" data={chartData}>
          <PolarGrid stroke="#444" />
          <PolarAngleAxis dataKey="subject" tick={{ fill: '#888', fontSize: 10 }} />
          <PolarRadiusAxis angle={30} domain={[0, 100]} tick={false} axisLine={false} />
          <Radar
            name="Target Style"
            dataKey="A"
            stroke="#fbbf24"
            fill="#fbbf24"
            fillOpacity={0.6}
          />
        </ReRadarChart>
      </ResponsiveContainer>
    </div>
  );
};

import React from 'react';
