import React, { useState, useCallback, useEffect, useRef } from 'react';
import { 
  Upload, Sparkles, Sliders, ChevronRight, 
  Layers, Database, Zap, ArrowRight, Loader2, Camera
} from 'lucide-react';
import { GeminiService } from './services/geminiService';
import { StyleVector, ProcessingStep, WoodTensor } from './types';
import { MOCK_WOOD_TENSORS, INITIAL_STYLE } from './constants';
import { RadarChart } from './components/RadarChart';
import { CompassDial } from './components/CompassDial';

const App: React.FC = () => {
  const [step, setStep] = useState<ProcessingStep>(ProcessingStep.IDLE);
  const [uploadedImage, setUploadedImage] = useState<string | null>(null);
  const [styleVector, setStyleVector] = useState<StyleVector>(INITIAL_STYLE);
  const [currentAngle, setCurrentAngle] = useState(90);
  const [optimalAngle, setOptimalAngle] = useState(0);
  const [generatedImage, setGeneratedImage] = useState<string | null>(null);
  const [prompt, setPrompt] = useState('');

  const geminiRef = useRef<GeminiService | null>(null);

  useEffect(() => {
    geminiRef.current = new GeminiService();
  }, []);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setUploadedImage(reader.result as string);
        analyzeStyle(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const analyzeStyle = async (image: string) => {
    if (!geminiRef.current) return;
    setStep(ProcessingStep.ENCODING_TARGET);
    try {
      const vector = await geminiRef.current.encodeTargetStyle(image);
      setStyleVector(vector);
      calculateOptimalAngle(vector);
    } catch (error) {
      console.error("Analysis failed", error);
    } finally {
      setStep(ProcessingStep.IDLE);
    }
  };

  const calculateOptimalAngle = (vector: StyleVector) => {
    // Layer 3 Logic Simulation: argmin ||V_t - V_w(theta)||
    // We map style features to goniometric wood properties
    // e.g. "Luxury" likes "Reflectivity", "Natural" likes "GrainComplexity"
    let bestAngle = 0;
    let minDistance = Infinity;

    MOCK_WOOD_TENSORS.forEach(wood => {
      const distance = Math.sqrt(
        Math.pow(vector.luxury - wood.reflectivity, 2) +
        Math.pow(vector.natural - wood.grainComplexity, 2) +
        Math.pow(vector.classical - wood.depth, 2)
      );
      if (distance < minDistance) {
        minDistance = distance;
        bestAngle = wood.angle;
      }
    });

    setOptimalAngle(bestAngle);
    setCurrentAngle(bestAngle);
  };

  const handleGenerate = async () => {
    if (!geminiRef.current) return;
    setStep(ProcessingStep.GENERATING);
    try {
      const wood = MOCK_WOOD_TENSORS.find(w => w.angle === currentAngle) || MOCK_WOOD_TENSORS[0];
      const semanticPrompt = await geminiRef.current.generateSemanticPrompt(styleVector, wood);
      setPrompt(semanticPrompt);
      const img = await geminiRef.current.generateFurniture(semanticPrompt, uploadedImage || undefined);
      setGeneratedImage(img);
    } catch (error) {
      console.error("Generation failed", error);
    } finally {
      setStep(ProcessingStep.IDLE);
    }
  };

  return (
    <div className="flex flex-col h-screen overflow-hidden bg-stone-950">
      {/* Header */}
      <header className="h-16 border-b border-stone-800 flex items-center justify-between px-8 bg-stone-900/50 backdrop-blur-md z-50">
        <div className="flex items-center gap-3">
          <div className="w-8 h-8 bg-amber-500 rounded-lg flex items-center justify-center">
            <Layers className="text-stone-950 w-5 h-5" />
          </div>
          <h1 className="text-lg font-bold tracking-tight">PHOEBE ZHENNAN <span className="text-amber-500">AI</span></h1>
        </div>
        <div className="flex items-center gap-6 text-xs font-medium text-stone-500 uppercase tracking-widest">
          <div className="flex items-center gap-2"><Database className="w-4 h-4" /> Data Layer</div>
          <ArrowRight className="w-3 h-3" />
          <div className="flex items-center gap-2"><Zap className="w-4 h-4" /> Perception</div>
          <ArrowRight className="w-3 h-3" />
          <div className="flex items-center gap-2"><Sliders className="w-4 h-4" /> Reasoning</div>
          <ArrowRight className="w-3 h-3" />
          <div className="flex items-center gap-2"><Sparkles className="w-4 h-4" /> Generation</div>
        </div>
      </header>

      <main className="flex-1 flex overflow-hidden p-6 gap-6">
        {/* Left Panel: Perception & Data */}
        <section className="w-1/4 flex flex-col gap-6">
          <div className="flex-1 bg-stone-900/40 border border-stone-800 rounded-2xl p-6 flex flex-col">
            <div className="flex items-center justify-between mb-6">
              <h2 className="text-sm font-bold flex items-center gap-2 uppercase tracking-tighter text-stone-400">
                <Upload className="w-4 h-4" /> Input Stream
              </h2>
            </div>

            <div className="relative flex-1 rounded-xl border-2 border-dashed border-stone-800 hover:border-amber-500/50 transition-colors flex flex-col items-center justify-center p-4 text-center group">
              {uploadedImage ? (
                <img src={uploadedImage} alt="Input" className="w-full h-full object-cover rounded-lg" />
              ) : (
                <>
                  <Camera className="w-10 h-10 text-stone-700 mb-4 group-hover:text-amber-500 transition-colors" />
                  <p className="text-sm text-stone-500 mb-4">Upload 3D Model, Sketch, or Image</p>
                </>
              )}
              <input 
                type="file" 
                className="absolute inset-0 opacity-0 cursor-pointer" 
                onChange={handleFileUpload} 
                accept="image/*"
              />
            </div>

            <div className="mt-6 space-y-4">
              <RadarChart data={styleVector} />

              <div className="bg-stone-800/30 p-4 rounded-xl border border-stone-800">
                <div className="text-[10px] text-stone-500 uppercase font-bold mb-2">Target Encoder Status</div>
                <div className="flex items-center gap-2">
                  <div className={`w-2 h-2 rounded-full ${step === ProcessingStep.ENCODING_TARGET ? 'bg-amber-500 animate-pulse' : 'bg-stone-600'}`}></div>
                  <span className="text-xs text-stone-300">
                    {step === ProcessingStep.ENCODING_TARGET ? 'Analyzing Semantic Features...' : 'Stream Idle'}
                  </span>
                </div>
              </div>
            </div>
          </div>
        </section>

        {/* Center Panel: Visualization */}
        <section className="flex-1 flex flex-col gap-6">
          <div className="flex-1 bg-stone-900 border border-stone-800 rounded-3xl relative overflow-hidden flex items-center justify-center shadow-2xl">
            {generatedImage ? (
              <img src={generatedImage} alt="Generated" className="w-full h-full object-contain" />
            ) : (
              <div className="text-center">
                {step === ProcessingStep.GENERATING ? (
                  <div className="space-y-4">
                    <Loader2 className="w-12 h-12 text-amber-500 animate-spin mx-auto" />
                    <p className="text-amber-500 font-mono text-sm animate-pulse">Running SD Pipeline + IP-Adapter...</p>
                  </div>
                ) : (
                  <div className="space-y-4 text-stone-700">
                    <Sparkles className="w-20 h-20 mx-auto opacity-20" />
                    <p className="max-w-xs text-sm">Semantic Optimization logic calculated. Click generate to visualize the Phoebe Zhennan wood grain.</p>
                  </div>
                )}
              </div>
            )}

            {/* HUD Overlays */}
            <div className="absolute top-6 left-6 flex gap-2">
              <span className="px-3 py-1 bg-stone-950/80 border border-stone-700 text-[10px] rounded-full text-stone-400 font-mono">MODEL: GEMINI-IMAGE-V2.5</span>
              <span className="px-3 py-1 bg-stone-950/80 border border-stone-700 text-[10px] rounded-full text-stone-400 font-mono">LAYER: GENERATIVE VIS</span>
            </div>
          </div>

          <div className="h-32 bg-stone-900/60 border border-stone-800 rounded-2xl p-4 flex items-center gap-6 overflow-x-auto no-scrollbar">
            <div className="flex-none w-48 text-[10px] text-stone-500 uppercase font-bold tracking-tighter">
              Parametric Prompt Mechanism
            </div>
            <div className="flex-1 font-mono text-xs text-stone-400 line-clamp-3 bg-black/40 p-3 rounded-lg border border-stone-800 italic">
              {prompt || "Semantic prompts will be mapped based on optimal goniometric calculations..."}
            </div>
            <button 
              onClick={handleGenerate}
              disabled={step !== ProcessingStep.IDLE || !uploadedImage}
              className="flex-none px-8 py-3 bg-amber-500 hover:bg-amber-400 disabled:bg-stone-800 disabled:text-stone-600 rounded-xl text-stone-950 font-bold uppercase text-sm flex items-center gap-2 transition-all active:scale-95 shadow-lg shadow-amber-500/20"
            >
              <Sparkles className="w-4 h-4" /> Synthesize
            </button>
          </div>
        </section>

        {/* Right Panel: Logic & Reasoning */}
        <section className="w-1/4 flex flex-col gap-6">
          <div className="flex-1 bg-stone-900/40 border border-stone-800 rounded-2xl p-6 flex flex-col">
            <h2 className="text-sm font-bold flex items-center gap-2 uppercase tracking-tighter text-stone-400 mb-10">
              <Sliders className="w-4 h-4" /> Intelligent Reasoning
            </h2>

            <div className="flex-1 flex flex-col items-center justify-center space-y-12">
              <CompassDial 
                value={currentAngle} 
                onChange={setCurrentAngle} 
                optimalValue={optimalAngle}
              />

              <div className="w-full space-y-4">
                <div className="flex justify-between items-center text-[10px] uppercase font-bold text-stone-500">
                  <span>Optimization Objective</span>
                  <span className="text-emerald-500">argmin ||V_t - V_w(θ)||</span>
                </div>

                <div className="grid grid-cols-2 gap-3">
                  <div className="bg-stone-800/50 p-3 rounded-lg border border-stone-700">
                    <div className="text-[9px] text-stone-500 uppercase">Reflectivity</div>
                    <div className="text-lg font-mono text-amber-500">{(MOCK_WOOD_TENSORS.find(w => w.angle === currentAngle)?.reflectivity || 0).toFixed(3)}</div>
                  </div>
                  <div className="bg-stone-800/50 p-3 rounded-lg border border-stone-700">
                    <div className="text-[9px] text-stone-500 uppercase">Chatoyancy</div>
                    <div className="text-lg font-mono text-amber-500">{(MOCK_WOOD_TENSORS.find(w => w.angle === currentAngle)?.grainComplexity || 0).toFixed(3)}</div>
                  </div>
                </div>

                <div className="bg-emerald-500/10 border border-emerald-500/20 p-4 rounded-xl mt-4">
                  <div className="text-[10px] text-emerald-500 font-bold uppercase mb-1">Logic Insight</div>
                  <p className="text-xs text-stone-300 leading-relaxed italic">
                    The {styleVector.luxury > 0.6 ? 'high luxury' : 'subtle'} profile suggests an optimal goniometric angle of <span className="text-emerald-400 font-bold">{optimalAngle}°</span> for maximum chatoyancy.
                  </p>
                </div>
              </div>
            </div>

            <div className="mt-8 pt-8 border-t border-stone-800">
              <div className="flex items-center justify-between text-[10px] text-stone-500 font-bold uppercase mb-4">
                <span>Dual-Stream Sync</span>
                <span className="text-amber-500">98.4% Match</span>
              </div>
              <div className="w-full h-1 bg-stone-800 rounded-full overflow-hidden">
                <div className="h-full bg-amber-500 w-[98.4%]"></div>
              </div>
            </div>
          </div>
        </section>
      </main>

      {/* Footer Info */}
      <footer className="h-10 border-t border-stone-800 px-8 flex items-center justify-between bg-stone-900/80 text-[10px] text-stone-500 font-mono tracking-widest uppercase">
        <div className="flex items-center gap-4">
          <span>RESNET-152: ACTIVE</span>
          <span>|</span>
          <span>CONTROLNET: DEPTH_MAP_LOADED</span>
        </div>
        <div>STABLE DIFFUSION XL • PHOEBE_ZHENNAN_V3</div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { 
  Upload, Sparkles, Sliders, Layers, Database, 
  Zap, ArrowRight, Loader2, Camera, AlertTriangle
} from 'lucide-react';
import { GeminiService } from './services/geminiService';
import { StyleVector, ProcessingStep } from './types';
import { MOCK_WOOD_TENSORS, INITIAL_STYLE } from './constants';
import { RadarChart } from './components/RadarChart';
import { CompassDial } from './components/CompassDial';

const App: React.FC = () => {
  const [step, setStep] = useState<ProcessingStep>(ProcessingStep.IDLE);
  const [uploadedImage, setUploadedImage] = useState<string | null>(null);
  const [styleVector, setStyleVector] = useState<StyleVector>(INITIAL_STYLE);
  const [currentAngle, setCurrentAngle] = useState(90);
  const [optimalAngle, setOptimalAngle] = useState(0);
  const [generatedImage, setGeneratedImage] = useState<string | null>(null);
  const [prompt, setPrompt] = useState('');
  const [error, setError] = useState<string | null>(null);

  const geminiRef = useRef<GeminiService | null>(null);

  useEffect(() => {
    try {
      geminiRef.current = new GeminiService();
    } catch (err) {
      console.error("Service initialization failed:", err);
      setError("Failed to initialize Gemini AI Service. Please check API configuration.");
    }
  }, []);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setError(null);
      const reader = new FileReader();
      reader.onloadend = () => {
        setUploadedImage(reader.result as string);
        analyzeStyle(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const analyzeStyle = async (image: string) => {
    if (!geminiRef.current) return;
    setStep(ProcessingStep.ENCODING_TARGET);
    try {
      const vector = await geminiRef.current.encodeTargetStyle(image);
      setStyleVector(vector);
      calculateOptimalAngle(vector);
    } catch (err) {
      console.error("Analysis failed", err);
      setError("Style analysis failed. Please try a different image.");
    } finally {
      setStep(ProcessingStep.IDLE);
    }
  };

  const calculateOptimalAngle = (vector: StyleVector) => {
    let bestAngle = 0;
    let minDistance = Infinity;

    MOCK_WOOD_TENSORS.forEach(wood => {
      // Euclidean distance in semantic space mapping target style to wood properties
      const distance = Math.sqrt(
        Math.pow(vector.luxury - wood.reflectivity, 2) +
        Math.pow(vector.natural - wood.grainComplexity, 2) +
        Math.pow(vector.classical - wood.depth, 2)
      );
      if (distance < minDistance) {
        minDistance = distance;
        bestAngle = wood.angle;
      }
    });

    setOptimalAngle(bestAngle);
    setCurrentAngle(bestAngle);
  };

  const handleGenerate = async () => {
    if (!geminiRef.current) return;
    setStep(ProcessingStep.GENERATING);
    setError(null);
    try {
      const wood = MOCK_WOOD_TENSORS.find(w => w.angle === currentAngle) || MOCK_WOOD_TENSORS[0];
      const semanticPrompt = await geminiRef.current.generateSemanticPrompt(styleVector, wood);
      setPrompt(semanticPrompt);
      const img = await geminiRef.current.generateFurniture(semanticPrompt, uploadedImage || undefined);
      if (!img) throw new Error("No image generated");
      setGeneratedImage(img);
    } catch (err) {
      console.error("Generation failed", err);
      setError("Image synthesis failed. Please try again.");
    } finally {
      setStep(ProcessingStep.IDLE);
    }
  };

  return (
    <div className="flex flex-col h-screen overflow-hidden bg-stone-950 text-stone-100 font-sans">
      {/* Header */}
