import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App.tsx';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useEffect, useRef } from 'react';
import { 
  Upload, Sparkles, Sliders, Layers, Database, 
  Zap, ArrowRight, Loader2, Camera, AlertTriangle
} from 'lucide-react';
import { GeminiService } from './services/geminiService.ts';
import { StyleVector, ProcessingStep } from './types.ts';
import { MOCK_WOOD_TENSORS, INITIAL_STYLE } from './constants.ts';
import { RadarChart } from './components/RadarChart.tsx';
import { CompassDial } from './components/CompassDial.tsx';

const App: React.FC = () => {
  const [step, setStep] = useState<ProcessingStep>(ProcessingStep.IDLE);
  const [uploadedImage, setUploadedImage] = useState<string | null>(null);
  const [styleVector, setStyleVector] = useState<StyleVector>(INITIAL_STYLE);
  const [currentAngle, setCurrentAngle] = useState(90);
  const [optimalAngle, setOptimalAngle] = useState(0);
  const [generatedImage, setGeneratedImage] = useState<string | null>(null);
  const [prompt, setPrompt] = useState('');
  const [error, setError] = useState<string | null>(null);

  const geminiRef = useRef<GeminiService | null>(null);

  useEffect(() => {
    try {
      geminiRef.current = new GeminiService();
    } catch (err) {
      console.error("Service init failed:", err);
      setError("AI服务初始化失败，请检查环境配置。");
    }
  }, []);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setError(null);
      const reader = new FileReader();
      reader.onloadend = () => {
        setUploadedImage(reader.result as string);
        analyzeStyle(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const analyzeStyle = async (image: string) => {
    if (!geminiRef.current) return;
    setStep(ProcessingStep.ENCODING_TARGET);
    try {
      const vector = await geminiRef.current.encodeTargetStyle(image);
      setStyleVector(vector);
      calculateOptimalAngle(vector);
    } catch (err) {
      console.error("Analysis failed", err);
      setError("风格意象解析失败，请尝试其他图片。");
    } finally {
      setStep(ProcessingStep.IDLE);
    }
  };

  const calculateOptimalAngle = (vector: StyleVector) => {
    let bestAngle = 0;
    let minDistance = Infinity;

    MOCK_WOOD_TENSORS.forEach(wood => {
      const distance = Math.sqrt(
        Math.pow(vector.luxury - wood.reflectivity, 2) +
        Math.pow(vector.natural - wood.grainComplexity, 2) +
        Math.pow(vector.classical - wood.depth, 2)
      );
      if (distance < minDistance) {
        minDistance = distance;
        bestAngle = wood.angle;
      }
    });

    setOptimalAngle(bestAngle);
    setCurrentAngle(bestAngle);
  };

  const handleGenerate = async () => {
    if (!geminiRef.current) return;
    setStep(ProcessingStep.GENERATING);
    setError(null);
    try {
      const wood = MOCK_WOOD_TENSORS.find(w => w.angle === currentAngle) || MOCK_WOOD_TENSORS[0];
      const semanticPrompt = await geminiRef.current.generateSemanticPrompt(styleVector, wood);
      setPrompt(semanticPrompt);
      const img = await geminiRef.current.generateFurniture(semanticPrompt, uploadedImage || undefined);
      if (!img) throw new Error("Generation empty");
      setGeneratedImage(img);
    } catch (err) {
      console.error("Generation failed", err);
      setError("图像合成失败。");
    } finally {
      setStep(ProcessingStep.IDLE);
    }
  };

  return (
    <div className="flex flex-col h-screen overflow-hidden bg-stone-950 text-stone-100">
      {/* Header */}
      <header className="h-16 border-b border-stone-800 flex items-center justify-between px-8 bg-stone-900/50 backdrop-blur-md z-50 flex-shrink-0">
        <div className="flex items-center gap-3">
          <div className="w-8 h-8 bg-amber-500 rounded-lg flex items-center justify-center">
            <Layers className="text-stone-950 w-5 h-5" />
          </div>
          <h1 className="text-lg font-bold tracking-tight">PHOEBE ZHENNAN <span className="text-amber-500">AI</span></h1>
        </div>
        <div className="hidden lg:flex items-center gap-6 text-[10px] font-medium text-stone-500 uppercase tracking-widest">
          <div className="flex items-center gap-2"><Database className="w-3 h-3" /> 数据层</div>
          <ArrowRight className="w-3 h-3 opacity-30" />
          <div className="flex items-center gap-2"><Zap className="w-3 h-3" /> 感知层</div>
          <ArrowRight className="w-3 h-3 opacity-30" />
          <div className="flex items-center gap-2"><Sliders className="w-3 h-3" /> 推理层</div>
          <ArrowRight className="w-3 h-3 opacity-30" />
          <div className="flex items-center gap-2"><Sparkles className="w-3 h-3" /> 生成层</div>
        </div>
      </header>

      {/* Main Layout */}
      <main className="flex-1 flex overflow-hidden p-4 md:p-6 gap-6">
        {/* Left Side: Perception Data */}
        <aside className="w-80 flex-shrink-0 flex flex-col gap-6 overflow-y-auto no-scrollbar">
          <div className="bg-stone-900/40 border border-stone-800 rounded-2xl p-5 flex flex-col shadow-xl">
            <h2 className="text-xs font-bold flex items-center gap-2 uppercase tracking-tighter text-stone-500 mb-4">
              <Upload className="w-3 h-3" /> 输入意象
            </h2>

            <div className="aspect-square relative rounded-xl border-2 border-dashed border-stone-800 hover:border-amber-500/50 transition-all flex flex-col items-center justify-center p-2 text-center group cursor-pointer bg-stone-950/20">
              {uploadedImage ? (
                <img src={uploadedImage} alt="Input" className="w-full h-full object-cover rounded-lg" />
              ) : (
                <div className="p-4">
                  <Camera className="w-8 h-8 text-stone-700 mb-2 mx-auto group-hover:text-amber-500 transition-colors" />
                  <p className="text-[10px] text-stone-500 uppercase tracking-wider">上传家具造型/草图</p>
                </div>
              )}
              <input 
                type="file" 
                className="absolute inset-0 opacity-0 cursor-pointer" 
                onChange={handleFileUpload} 
                accept="image/*"
              />
            </div>

            <div className="mt-6 h-64">
              <RadarChart data={styleVector} />
            </div>

            <div className="mt-4 bg-stone-800/20 p-3 rounded-xl border border-stone-800/50">
              <div className="text-[9px] text-stone-500 uppercase font-bold mb-1">感知层状态 (Perception Status)</div>
              <div className="flex items-center gap-2">
                <div className={`w-1.5 h-1.5 rounded-full ${step === ProcessingStep.ENCODING_TARGET ? 'bg-amber-500 animate-pulse' : 'bg-emerald-500'}`}></div>
                <span className="text-[10px] text-stone-400 font-mono">
                  {step === ProcessingStep.ENCODING_TARGET ? 'ENCODING_STREAMING...' : 'LAYER_A: READY'}
                </span>
              </div>
            </div>
          </div>
        </aside>

        {/* Center Side: Generator */}
        <section className="flex-1 flex flex-col gap-6">
          <div className="flex-1 bg-stone-900 border border-stone-800 rounded-3xl relative overflow-hidden flex items-center justify-center shadow-2xl">
            {error && (
              <div className="absolute inset-0 z-20 flex items-center justify-center bg-stone-950/80 backdrop-blur-md">
                <div className="text-center p-8 bg-stone-900 border border-red-900/30 rounded-2xl max-w-sm">
                  <AlertTriangle className="w-12 h-12 text-red-500 mx-auto mb-4" />
                  <p className="text-sm text-stone-300">{error}</p>
                  <button onClick={() => setError(null)} className="mt-6 px-6 py-2 bg-stone-800 hover:bg-stone-700 rounded-full text-xs uppercase font-bold transition-colors">确认</button>
                </div>
              </div>
            )}

            {generatedImage ? (
              <img src={generatedImage} alt="Generated" className="w-full h-full object-contain" />
            ) : (
              <div className="text-center px-10">
                {step === ProcessingStep.GENERATING ? (
                  <div className="space-y-4">
                    <Loader2 className="w-10 h-10 text-amber-500 animate-spin mx-auto opacity-80" />
                    <p className="text-amber-500 font-mono text-[10px] animate-pulse tracking-[0.2em] uppercase">正在合成物理材质与几何空间...</p>
                  </div>
                ) : (
                  <div className="space-y-3 opacity-20">
                    <Sparkles className="w-16 h-16 mx-auto text-stone-500" />
                    <p className="text-[11px] uppercase tracking-widest text-stone-500">等待推理层决策输出</p>
                  </div>
                )}
              </div>
            )}

            <div className="absolute top-6 left-6 flex flex-col gap-2">
              <div className="px-3 py-1 bg-stone-950/80 border border-stone-800 text-[9px] rounded-sm text-stone-400 font-mono">CORE_VERSION: 3.1_PRO</div>
              <div className="px-3 py-1 bg-stone-950/80 border border-stone-800 text-[9px] rounded-sm text-stone-400 font-mono">UI_REF: {uploadedImage ? 'ACTIVE' : 'NONE'}</div>
            </div>
          </div>

          <div className="h-28 bg-stone-900/40 border border-stone-800 rounded-2xl p-4 flex items-center gap-6 flex-shrink-0">
            <div className="flex-1 font-mono text-[11px] text-stone-500 line-clamp-2 bg-black/40 p-3 rounded-xl border border-stone-800/50 italic leading-relaxed">
              {prompt || "语义提示词将基于金丝楠木多角度变色(Chatoyancy)特性与家具造型意象自动映射..."}
            </div>
            <button 
              onClick={handleGenerate}
              disabled={step !== ProcessingStep.IDLE || !uploadedImage}
              className="flex-none px-8 py-3 bg-amber-500 hover:bg-amber-400 disabled:bg-stone-800 disabled:text-stone-600 rounded-xl text-stone-950 font-bold uppercase text-xs flex items-center gap-2 transition-all active:scale-95 shadow-xl shadow-amber-500/10"
            >
              <Sparkles className="w-4 h-4" /> 开始合成
            </button>
          </div>
        </section>

        {/* Right Side: Logic Reasoning */}
        <aside className="w-80 flex-shrink-0 flex flex-col gap-6">
          <div className="flex-1 bg-stone-900/40 border border-stone-800 rounded-2xl p-6 flex flex-col shadow-xl">
            <h2 className="text-xs font-bold flex items-center gap-2 uppercase tracking-tighter text-stone-500 mb-8">
              <Sliders className="w-3 h-3" /> 推理推理层 (Logic)
            </h2>

            <div className="flex-1 flex flex-col items-center justify-start space-y-10">
              <CompassDial 
                value={currentAngle} 
                onChange={setCurrentAngle} 
                optimalValue={optimalAngle}
              />

              <div className="w-full space-y-4">
                <div className="flex justify-between items-center text-[10px] uppercase font-bold text-stone-600 tracking-widest">
                  <span>最佳变色角度</span>
                  <span className="text-emerald-500 font-mono">{optimalAngle}°</span>
                </div>

                <div className="grid grid-cols-2 gap-2">
                  <div className="bg-black/20 p-3 rounded-lg border border-stone-800/50">
                    <div className="text-[9px] text-stone-500 uppercase mb-1">反射率 (Ref)</div>
                    <div className="text-base font-mono text-amber-500">{(MOCK_WOOD_TENSORS.find(w => w.angle === currentAngle)?.reflectivity || 0).toFixed(3)}</div>
                  </div>
                  <div className="bg-black/20 p-3 rounded-lg border border-stone-800/50">
                    <div className="text-[9px] text-stone-500 uppercase mb-1">纹理深度 (Depth)</div>
                    <div className="text-base font-mono text-amber-500">{(MOCK_WOOD_TENSORS.find(w => w.angle === currentAngle)?.depth || 0).toFixed(3)}</div>
                  </div>
                </div>

                <div className="bg-emerald-500/5 border border-emerald-500/10 p-4 rounded-xl">
                  <div className="text-[9px] text-emerald-500 font-bold uppercase mb-1 tracking-widest">物理特性映射结果</div>
                  <p className="text-[11px] text-stone-400 leading-relaxed italic">
                    当前选择的 {currentAngle}° 角，在{styleVector.luxury > 0.6 ? '极致奢华' : '自然'}意象空间中可提供极佳的光线交互反馈。
                  </p>
                </div>
              </div>
            </div>

            <div className="mt-auto pt-6 border-t border-stone-800/50">
              <div className="flex items-center justify-between text-[10px] text-stone-600 font-bold uppercase mb-3">
                <span>层间同步速率</span>
                <span className="text-amber-500/80 font-mono">1.2ms</span>
              </div>
              <div className="w-full h-1 bg-stone-800/50 rounded-full overflow-hidden">
                <div className="h-full bg-amber-500/50 w-[96%]"></div>
              </div>
            </div>
          </div>
        </aside>
      </main>

      <footer className="h-8 border-t border-stone-800 px-6 flex items-center justify-between bg-stone-900/90 text-[9px] text-stone-600 font-mono tracking-widest uppercase flex-shrink-0">
        <div className="flex items-center gap-5">
          <span className="flex items-center gap-1.5"><div className="w-1 h-1 bg-emerald-500 rounded-full"></div> RESNET_52_V3: ACTIVE</span>
          <span className="flex items-center gap-1.5"><div className="w-1 h-1 bg-emerald-500 rounded-full"></div> STABLE_DIFF_XL: READY</span>
        </div>
        <div>PHOEBE_ZHENNAN_INTELLIGENT_DESIGN_SYSTEM v2.0</div>
      </footer>
    </div>
  );
};

export default App;

import { GoogleGenAI, Type } from "@google/genai";
import { StyleVector, WoodTensor } from "../types.ts";

export class GeminiService {
  private ai: GoogleGenAI;

  constructor() {
    // 确保从正确的环境获取 API_KEY
    const apiKey = typeof process !== 'undefined' ? process.env.API_KEY : '';
    this.ai = new GoogleGenAI({ apiKey: apiKey || '' });
  }

  /**
   * 层 2: 目标编码器 (Stream A: Target Encoder)
   */
  async encodeTargetStyle(base64Image: string): Promise<StyleVector> {
    const response = await this.ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: [
        {
          parts: [
            { inlineData: { data: base64Image.split(',')[1], mimeType: 'image/jpeg' } },
            { text: "分析此家具图片的风格并返回意象向量（0-1）。关注点：古典、现代、自然感、几何感、奢华度。以JSON格式输出。" }
          ]
        }
      ],
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            classical: { type: Type.NUMBER },
            modern: { type: Type.NUMBER },
            natural: { type: Type.NUMBER },
            geometric: { type: Type.NUMBER },
            luxury: { type: Type.NUMBER }
          },
          required: ["classical", "modern", "natural", "geometric", "luxury"]
        }
      }
    });

    return JSON.parse(response.text);
  }

  /**
   * 层 3: 参数化 Prompt 映射
   */
  async generateSemanticPrompt(style: StyleVector, wood: WoodTensor): Promise<string> {
    const response = await this.ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `生成一段用于 Stable Diffusion 渲染的专业提示词。
      风格向量: 古典 ${style.classical}, 现代 ${style.modern}, 自然 ${style.natural}, 奢华 ${style.luxury}。
      木材特性: 金丝楠木（Phoebe Zhennan），在 ${wood.angle} 度光照下。
      要求描述出：移步换景的“金丝”动感，猫眼效应，丝绸质感的纤维结构，深邃的琥珀金光。
      技术规格: 渲染级光影, 物理精准, 8k, 极简背景。`,
    });
    return response.text;
  }

  /**
   * 层 4: 生成可视化
   */
  async generateFurniture(prompt: string, referenceImageBase64?: string): Promise<string> {
    const parts: any[] = [{ text: prompt }];
    if (referenceImageBase64) {
      parts.push({
        inlineData: {
          data: referenceImageBase64.split(',')[1],
          mimeType: 'image/jpeg'
        }
      });
    }

    const response = await this.ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: { parts },
      config: {
        imageConfig: {
          aspectRatio: "1:1"
        }
      }
    });

    let imageUrl = '';
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        imageUrl = `data:image/png;base64,${part.inlineData.data}`;
        break;
      }
    }
    return imageUrl;
  }
}

import { GoogleGenAI, Type } from "@google/genai";
