import React, { useState, useEffect, useRef } from 'react';
import { 
  Upload, Sparkles, Sliders, Layers, Database, 
  Zap, ArrowRight, Loader2, Camera, AlertTriangle
} from 'lucide-react';
import { GeminiService } from './services/geminiService.ts';
import { StyleVector, ProcessingStep } from './types.ts';
import { MOCK_WOOD_TENSORS, INITIAL_STYLE } from './constants.ts';
import { RadarChart } from './components/RadarChart.tsx';
import { CompassDial } from './components/CompassDial.tsx';

/**
 * App component for the Chatoyancy.AI furniture design platform.
 * Follows @google/genai guidelines for Gemini 3 and 2.5 Flash models.
 */
const App: React.FC = () => {
  const [step, setStep] = useState<ProcessingStep>(ProcessingStep.IDLE);
  const [uploadedImage, setUploadedImage] = useState<string | null>(null);
  const [styleVector, setStyleVector] = useState<StyleVector>(INITIAL_STYLE);
  const [currentAngle, setCurrentAngle] = useState(90);
  const [optimalAngle, setOptimalAngle] = useState(0);
  const [generatedImage, setGeneratedImage] = useState<string | null>(null);
  const [prompt, setPrompt] = useState('');
  const [error, setError] = useState<string | null>(null);

  const geminiRef = useRef<GeminiService | null>(null);

  useEffect(() => {
    try {
      // Initialize the service that handles Gemini API interactions
      geminiRef.current = new GeminiService();
      console.log("Design Core Initialized.");
    } catch (err) {
      console.error("Design Core Error:", err);
      setError("AI 推理引擎初始化失败。");
    }

    // Cleanup global loader if present
    const loader = document.getElementById('loader');
    if (loader) {
      loader.style.opacity = '0';
      setTimeout(() => loader.remove(), 500);
    }
  }, []);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setError(null);
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64 = reader.result as string;
        setUploadedImage(base64);
        analyzeStyle(base64);
      };
      reader.onerror = () => setError("图片读取失败");
      reader.readAsDataURL(file);
    }
  };

  /**
   * Layer 2: Target Encoder
   * Analyzes uploaded image to extract style semantic vectors
   */
  const analyzeStyle = async (image: string) => {
    if (!geminiRef.current) return;
    setStep(ProcessingStep.ENCODING_TARGET);
    try {
      const vector = await geminiRef.current.encodeTargetStyle(image);
      setStyleVector(vector);
      calculateOptimalAngle(vector);
    } catch (err) {
      console.error("Perception Error:", err);
      setError("意象感知解析失败。");
    } finally {
      setStep(ProcessingStep.IDLE);
    }
  };

  /**
   * Layer 3: Parameter Mapping
   * Finds the optimal goniometric angle based on wood physical properties and style intent
   */
  const calculateOptimalAngle = (vector: StyleVector) => {
    let bestAngle = 0;
    let minDistance = Infinity;

    MOCK_WOOD_TENSORS.forEach(wood => {
      // Semantic-to-Physical mapping logic
      // Luxury matches reflectivity, Natural matches grain complexity
      const styleMetric = (vector.luxury * 0.4 + vector.natural * 0.3 + vector.modern * 0.3);
      const woodMetric = (wood.reflectivity * 0.4 + wood.warmth * 0.3 + wood.grainComplexity * 0.3);
      const distance = Math.abs(styleMetric - woodMetric);

      if (distance < minDistance) {
        minDistance = distance;
        bestAngle = wood.angle;
      }
    });
    setOptimalAngle(bestAngle);
    setCurrentAngle(bestAngle);
  };

  /**
   * Layer 4: Final Synthesis
   * Generates the final high-fidelity render with Gemini 2.5 Flash Image
   */
  const handleGenerate = async () => {
    if (!geminiRef.current || !uploadedImage) return;
    setStep(ProcessingStep.OPTIMIZING);
    try {
      const wood = MOCK_WOOD_TENSORS.find(w => w.angle === currentAngle) || MOCK_WOOD_TENSORS[0];
      const promptText = await geminiRef.current.generateSemanticPrompt(styleVector, wood);
      setPrompt(promptText);

      setStep(ProcessingStep.GENERATING);
      const url = await geminiRef.current.generateFurniture(promptText, uploadedImage);
      setGeneratedImage(url);
    } catch (err) {
      console.error("Generation Error:", err);
      setError("图像生成失败。");
    } finally {
      setStep(ProcessingStep.IDLE);
    }
  };

  return (
    <div className="min-h-screen bg-stone-950 text-stone-200 selection:bg-amber-500/30">
      {/* Header Navigation */}
      <nav className="border-b border-stone-800 bg-stone-900/50 backdrop-blur-md sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="w-8 h-8 bg-amber-500 rounded-lg flex items-center justify-center">
              <Sparkles className="text-black w-5 h-5" />
            </div>
            <span className="font-bold tracking-tight text-xl">CHATOYANCY<span className="text-amber-500">.AI</span></span>
          </div>
          <div className="hidden sm:flex items-center gap-4 text-xs font-medium text-stone-500">
            <span className="flex items-center gap-1"><Database className="w-3 h-3" /> TENSOR-V3</span>
            <span className="flex items-center gap-1"><Zap className="w-3 h-3 text-amber-500" /> LIVE-RENDER</span>
          </div>
        </div>
      </nav>

      <main className="max-w-7xl mx-auto p-4 md:p-8 grid grid-cols-1 lg:grid-cols-12 gap-8">
        {/* Left Column: Analysis & Configuration */}
        <div className="lg:col-span-4 space-y-6">
          <section className="bg-stone-900 border border-stone-800 rounded-2xl p-6">
            <h2 className="text-sm font-bold uppercase tracking-widest text-stone-500 mb-6 flex items-center gap-2">
              <Camera className="w-4 h-4" /> 1. Style Encoding
            </h2>

            <div className="relative group">
              <label className={`
                flex flex-col items-center justify-center w-full aspect-square rounded-xl border-2 border-dashed 
                transition-all cursor-pointer overflow-hidden
                ${uploadedImage ? 'border-amber-500/50 bg-amber-500/5' : 'border-stone-700 hover:border-stone-500 bg-stone-800/50'}
              `}>
                {uploadedImage ? (
                  <img src={uploadedImage} alt="Uploaded" className="w-full h-full object-cover" />
                ) : (
                  <div className="text-center p-6">
                    <Upload className="w-10 h-10 text-stone-600 mx-auto mb-4 group-hover:text-stone-400 transition-colors" />
                    <p className="text-sm text-stone-400">Upload Furniture Design</p>
                    <p className="text-[10px] text-stone-600 mt-2">RAW, JPEG, PNG (MAX 5MB)</p>
                  </div>
                )}
                <input type="file" className="hidden" onChange={handleFileUpload} accept="image/*" />
              </label>
              {uploadedImage && (
                <div className="absolute top-2 right-2">
                  <button onClick={() => setUploadedImage(null)} className="p-1 bg-black/50 backdrop-blur rounded-md hover:bg-black">
                    <AlertTriangle className="w-4 h-4 text-white" />
                  </button>
                </div>
              )}
            </div>

            <div className="mt-8">
              <RadarChart data={styleVector} />
            </div>
          </section>

          <section className="bg-stone-900 border border-stone-800 rounded-2xl p-6">
            <h2 className="text-sm font-bold uppercase tracking-widest text-stone-500 mb-6 flex items-center gap-2">
              <Sliders className="w-4 h-4" /> 2. Goniometric Control
            </h2>
            <CompassDial value={currentAngle} onChange={setCurrentAngle} optimalValue={optimalAngle} />
            <div className="mt-6 p-4 bg-stone-800/30 rounded-lg border border-stone-700/50">
              <div className="flex justify-between text-[10px] uppercase font-bold text-stone-500 mb-2">
                <span>Phase Shift</span>
                <span className="text-amber-500">Optimized</span>
              </div>
              <p className="text-xs leading-relaxed text-stone-400">
                Adjusting the viewing angle changes the chatoyancy intensity based on the timber's fiber orientation.
              </p>
            </div>
          </section>
        </div>

        {/* Right Column: Visualization & Rendering */}
        <div className="lg:col-span-8 space-y-6">
          <section className="bg-stone-900 border border-stone-800 rounded-2xl p-6 min-h-[600px] flex flex-col">
            <div className="flex items-center justify-between mb-6">
              <h2 className="text-sm font-bold uppercase tracking-widest text-stone-500 flex items-center gap-2">
                <Layers className="w-4 h-4" /> 3. Material Synthesis
              </h2>
              {step !== ProcessingStep.IDLE && (
                <div className="flex items-center gap-2 text-amber-500 text-xs font-mono animate-pulse">
                  <Loader2 className="w-3 h-3 animate-spin" /> {step}...
                </div>
              )}
            </div>

            <div className="flex-1 bg-stone-950 rounded-xl border border-stone-800 overflow-hidden relative group">
              {generatedImage ? (
                <img src={generatedImage} alt="Generated" className="w-full h-full object-contain" />
              ) : (
                <div className="w-full h-full flex flex-col items-center justify-center p-12 text-center">
                  <div className="w-24 h-24 bg-stone-900 rounded-3xl mb-6 flex items-center justify-center border border-stone-800">
                    <Sparkles className="w-10 h-10 text-stone-700" />
                  </div>
                  <h3 className="text-xl font-light text-stone-400">Ready for Synthesis</h3>
                  <p className="text-sm text-stone-600 mt-2 max-w-xs">
                    Upload an image and adjust the goniometric angle to generate a hyper-realistic furniture render.
                  </p>
                </div>
              )}

              {/* Overlay Prompt for inspection */}
              {prompt && (
                <div className="absolute bottom-4 left-4 right-4 p-4 bg-black/60 backdrop-blur-md rounded-lg border border-white/10 opacity-0 group-hover:opacity-100 transition-opacity">
                  <p className="text-[10px] text-stone-400 font-mono line-clamp-2">{prompt}</p>
                </div>
              )}
            </div>

            {error && (
              <div className="mt-4 p-4 bg-red-500/10 border border-red-500/20 rounded-lg flex items-center gap-3 text-red-400 text-sm">
                <AlertTriangle className="w-4 h-4" /> {error}
              </div>
            )}

            <button
              onClick={handleGenerate}
              disabled={!uploadedImage || step !== ProcessingStep.IDLE}
              className={`
                mt-6 w-full py-4 rounded-xl font-bold flex items-center justify-center gap-3 transition-all
                ${!uploadedImage || step !== ProcessingStep.IDLE 
                  ? 'bg-stone-800 text-stone-600 cursor-not-allowed' 
                  : 'bg-amber-500 text-black hover:bg-amber-400 active:scale-[0.98] shadow-lg shadow-amber-500/20'}
              `}
            >
              {step === ProcessingStep.IDLE ? (
                <>GENERATE SYNTHESIS <ArrowRight className="w-5 h-5" /></>
              ) : (
                <>PROCESSING NEURAL LAYERS... <Loader2 className="w-5 h-5 animate-spin" /></>
              )}
            </button>
          </section>

          {/* Real-time Material Tensors */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            <div className="bg-stone-900/50 border border-stone-800 p-4 rounded-xl">
              <div className="text-[10px] text-stone-500 uppercase font-bold mb-1">Optical Depth</div>
              <div className="text-xl font-mono text-stone-300">{(MOCK_WOOD_TENSORS.find(w => w.angle === currentAngle)?.depth || 0).toFixed(4)}</div>
            </div>
            <div className="bg-stone-900/50 border border-stone-800 p-4 rounded-xl">
              <div className="text-[10px] text-stone-500 uppercase font-bold mb-1">Reflectivity</div>
              <div className="text-xl font-mono text-stone-300">{(MOCK_WOOD_TENSORS.find(w => w.angle === currentAngle)?.reflectivity || 0).toFixed(4)}</div>
            </div>
            <div className="bg-stone-900/50 border border-stone-800 p-4 rounded-xl">
              <div className="text-[10px] text-stone-500 uppercase font-bold mb-1">Fiber Density</div>
              <div className="text-xl font-mono text-stone-300">{(MOCK_WOOD_TENSORS.find(w => w.angle === currentAngle)?.grainComplexity || 0).toFixed(4)}</div>
            </div>
          </div>
        </div>
      </main>
    </div>
  );
};

export default App;
